export type LText = { en: string; es: string };
export const text = (en: string, es: string): LText => ({ en, es });
export const pick = (v: LText, lang: Lang) => v[lang] || v.en;

export type GuideOption = { id: string; label: LText; domainPoints?: Partial<Record<DomainId, number>>; pathwayPoints?: Partial<Record<PathwayId, number>>; tags?: ContextTag[]; supportStyles?: SupportStyle[]; urgency?: number };
export type GuideQuestion = { id: string; stage: "profile" | "context" | "core" | "adaptive" | "support"; module?: PathwayId; prompt: LText; helper?: LText; inputType?: "single" | "multi" | "text"; maxSelections?: number; options: GuideOption[] };
export type GuideAnswers = Record<string, string | string[]>;

const opt = (id: string, en: string, es: string, extra: Omit<GuideOption, "id" | "label"> = {}): GuideOption => ({ id, label: text(en, es), ...extra });

